from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    if not search_results:
        return {}

    # Initialize aggregated data structure
    aggregated_data = defaultdict(lambda: {
        'items': [],
        'scores': [],
        'custom_stats': {}
    })

    # Process each search result
    for result in search_results:
        # Extract group value from metadata
        metadata = result.metadata or {}
        group_value = metadata.get(group_by_field)

        # Handle missing group field values
        if group_value is None or group_value == "":
            group_value = 'unknown'

        # Accumulate result data
        aggregated_data[group_value]['items'].append(result)
        aggregated_data[group_value]['scores'].append(result.score)

    # Compute default statistics for each group
    result_dict = {}
    for group_value, data in aggregated_data.items():
        # Calculate default statistics
        stats = {
            'count': len(data['items']),
            'avg_score': sum(data['scores']) / len(data['scores']) if data['scores'] else 0,
            'max_score': max(data['scores']) if data['scores'] else 0,
            'min_score': min(data['scores']) if data['scores'] else 0
        }

        # Apply custom aggregation functions if provided
        if aggregation_funcs:
            for field_name, func in aggregation_funcs.items():
                try:
                    # Extract relevant data for custom aggregation
                    if field_name == 'score':
                        values = data['scores']
                    else:
                        # Try to get field from metadata of all items in the group
                        values = []
                        for item in data['items']:
                            metadata = item.metadata or {}
                            values.append(metadata.get(field_name))

                        # Filter out non-numeric values for numeric operations
                        if field_name != 'score':
                            values = [v for v in values if isinstance(v, (int, float))]

                    # Apply the aggregation function
                    if values:
                        stats[field_name] = func(values)
                    else:
                        stats[field_name] = None
                except Exception as e:
                    stats[field_name] = f"Error: {str(e)}"

        result_dict[group_value] = stats

    return result_dict
